#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <assert.h>
#include <cuda_runtime.h>

void run(int argc, char** argv);

__inline__ uint64_t rdtsc() {
    uint32_t lo, hi;
    __asm__ __volatile__("rdtsc" : "=a"(lo), "=d"(hi));
    return ((uint64_t)hi << 32) | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc() - start_cycles)

#define pin_stats_reset() startCycle()
#define pin_stats_pause(cycles) stopCycle(cycles)
#define pin_stats_dump(cycles) printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

void init(int argc, char** argv) {
    if (argc == 3) {
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
    } else {
        printf("Usage: pathfiner width num_of_steps\n");
        exit(0);
    }

    data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; n < rows; n++) wall[n] = data + cols * n;
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            wall[i][j] = rand() % 10;
        }
    }

    for (int j = 0; j < cols; j++) result[j] = wall[0][j];

#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            printf("%d ", wall[i][j]);
        }
        printf("\n");
    }
#endif
}

void fatal(char* s) { fprintf(stderr, "error: %s\n", s); }

#define MIN(a, b) ((a) <= (b) ? (a) : (b))

static inline void cudaCheck(cudaError_t err, const char* msg) {
    if (err != cudaSuccess) {
        fprintf(stderr, "error: %s: %s\n", msg, cudaGetErrorString(err));
        exit(EXIT_FAILURE);
    }
}

__global__ void path_step_kernel(const int* src, int* dst, const int* wall_next_row, int cols) {
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n < cols) {
        int minv = src[n];
        if (n > 0) minv = MIN(minv, src[n - 1]);
        if (n < cols - 1) minv = MIN(minv, src[n + 1]);
        dst[n] = wall_next_row[n] + minv;
    }
}

int main(int argc, char** argv) {
    run(argc, argv);
    return EXIT_SUCCESS;
}

void run(int argc, char** argv) {
    init(argc, argv);

    unsigned long long cycles;
    int *src, *dst, *temp;

    dst = result;
    src = new int[cols];

    int* d_wall = nullptr;
    int* d_buf0 = nullptr;
    int* d_buf1 = nullptr;
    int* d_src = nullptr;
    int* d_dst = nullptr;

    cudaCheck(cudaMalloc((void**)&d_wall, sizeof(int) * rows * cols), "cudaMalloc d_wall");
    cudaCheck(cudaMalloc((void**)&d_buf0, sizeof(int) * cols), "cudaMalloc d_buf0");
    cudaCheck(cudaMalloc((void**)&d_buf1, sizeof(int) * cols), "cudaMalloc d_buf1");

    cudaCheck(cudaMemcpy(d_wall, data, sizeof(int) * rows * cols, cudaMemcpyHostToDevice), "cudaMemcpy wall");
    cudaCheck(cudaMemcpy(d_buf0, dst, sizeof(int) * cols, cudaMemcpyHostToDevice), "cudaMemcpy init result");

    d_dst = d_buf0;
    d_src = d_buf1;

    const int blockSize = 256;
    const int gridSize = (cols + blockSize - 1) / blockSize;

    pin_stats_reset();
    for (int t = 0; t < rows - 1; t++) {
        temp = src;
        src = dst;
        dst = temp;

        int* d_temp = d_src;
        d_src = d_dst;
        d_dst = d_temp;

        const int* d_wall_next = d_wall + (t + 1) * cols;
        path_step_kernel<<<gridSize, blockSize>>>(d_src, d_dst, d_wall_next, cols);
    }
    cudaCheck(cudaDeviceSynchronize(), "cudaDeviceSynchronize");
    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

    cudaCheck(cudaMemcpy(dst, d_dst, sizeof(int) * cols, cudaMemcpyDeviceToHost), "cudaMemcpy final dst");

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++) printf("%d ", data[i]);
    printf("\n");

    for (int i = 0; i < cols; i++) printf("%d ", dst[i]);
    printf("\n");
#endif

    cudaFree(d_wall);
    cudaFree(d_buf0);
    cudaFree(d_buf1);

    delete[] data;
    delete[] wall;
    delete[] dst;
    delete[] src;
}
